{
  "name": "syncplay",
  "version": "0.6.0",
  "description": "异地同步看片神器 — 两人异地同时播放同一视频，进度实时同步",
  "main": "src/server/server.js",
  "directories": {
    "test": "test"
  },
  "scripts": {
    "test": "node --test test/unit/*.test.js",
    "test:e2e": "node test/e2e/test.js",
    "test:ice": "node test/network/ice-smoke.js",
    "test:room": "node test/network/regression-create-room.js"
  },
  "keywords": [
    "webrtc",
    "video-sync",
    "p2p",
    "watch-together"
  ],
  "author": "Bruce",
  "license": "Apache-2.0",
  "devDependencies": {
    "playwright": "^1.58.2"
  }
}
